/**
 * Priority-based notification router.
 *
 * Maps notification priority levels to delivery channels:
 * - urgent → sms
 * - normal → email
 * - low → webhook
 *
 * Depends on: nothing (pure logic)
 */

import type { NotificationPriority } from '../events/event-types.js';

export type NotificationChannel = 'email' | 'sms' | 'webhook';

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, NotificationChannel> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export class PriorityRouter {
  /**
   * Resolve the delivery channel for a given notification priority.
   */
  route(priority: NotificationPriority): NotificationChannel {
    return PRIORITY_CHANNEL_MAP[priority];
  }
}

/**
 * Audit logging service for notification dispatch.
 *
 * Records every notification that is dispatched through the system,
 * capturing the notification details, channel used, priority, and timestamp.
 *
 * Subscribes to 'notification:requested' events on the EventBus.
 *
 * Depends on:
 * - EventBus (event system) for receiving notification events
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent, NotificationPriority } from '../events/event-types.js';
import type { NotificationChannel } from './priority-router.js';

export interface AuditLogEntry {
  notificationId: string;
  recipient: string;
  subject: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  timestamp: Date;
}

export class AuditService {
  private entries: AuditLogEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Subscribe to notification events for audit logging.
   */
  private registerHandlers(): void {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      this.record(event);
    });
  }

  /**
   * Record a notification dispatch in the audit log.
   */
  private record(event: NotificationRequestedEvent): void {
    this.entries.push({
      notificationId: event.notification.id,
      recipient: event.notification.recipient,
      subject: event.notification.subject,
      channel: event.channel,
      priority: event.priority,
      timestamp: event.timestamp,
    });
  }

  /**
   * Get all audit log entries.
   */
  getEntries(): AuditLogEntry[] {
    return [...this.entries];
  }

  /**
   * Get audit log entries for a specific notification.
   */
  getEntriesForNotification(notificationId: string): AuditLogEntry[] {
    return this.entries.filter((e) => e.notificationId === notificationId);
  }

  /**
   * Get audit log entries filtered by channel.
   */
  getEntriesByChannel(channel: NotificationChannel): AuditLogEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  /**
   * Clear all audit log entries (useful for testing).
   */
  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service.
 *
 * Allows per-user channel preferences that override the default
 * priority-based routing. When a user has a preference set for a
 * given priority level, that channel is used instead of the default.
 *
 * Depends on: nothing (pure state management)
 */

import type { NotificationPriority } from '../events/event-types.js';
import type { NotificationChannel } from './priority-router.js';

export interface UserNotificationPreferences {
  /** Override channel for each priority level. If not set, uses default routing. */
  channelOverrides: Partial<Record<NotificationPriority, NotificationChannel>>;
}

export class NotificationPreferencesService {
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Set a channel override for a user at a specific priority level.
   */
  setChannelOverride(userId: string, priority: NotificationPriority, channel: NotificationChannel): void {
    const prefs = this.preferences.get(userId) ?? { channelOverrides: {} };
    prefs.channelOverrides[priority] = channel;
    this.preferences.set(userId, prefs);
  }

  /**
   * Remove a channel override for a user at a specific priority level.
   */
  removeChannelOverride(userId: string, priority: NotificationPriority): void {
    const prefs = this.preferences.get(userId);
    if (prefs) {
      delete prefs.channelOverrides[priority];
    }
  }

  /**
   * Get the channel override for a user at a specific priority level, if any.
   */
  getChannelOverride(userId: string, priority: NotificationPriority): NotificationChannel | undefined {
    return this.preferences.get(userId)?.channelOverrides[priority];
  }

  /**
   * Get all preferences for a user.
   */
  getPreferences(userId: string): UserNotificationPreferences | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Clear all preferences (useful for testing).
   */
  clear(): void {
    this.preferences.clear();
  }
}

