}

parameters.new_string:
/**
 * Send a notification (in-memory for this demo).
 *
 * Routes to the appropriate channel via the PriorityRouter,
 * unless the user has a preference override via NotificationPreferencesService.
 */
sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
}): void {
  const defaultChannel = this.priorityRouter.route(params.priority);
  const channel = this.preferencesService?.getChannelOverride(params.recipient, params.priority)
    ?? defaultChannel;

  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient} via ${channel}`);

  // Publish event so channel handlers (SMS, webhook, etc.) and audit service can process it
  const event: NotificationRequestedEvent = {
    type: 'notification:requested',
    notification: {
      id: notification.id,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
    },
    channel,
    priority: params.priority,
    timestamp: new Date(),
  };
  void this.eventBus.emit(event);
}

